function solve(nums) {
    const n = nums.length;
    if (n < 2) return 0;
    const sorted_abs = nums.map(x => Math.abs(x)).sort((a, b) => a - b);
    let count = 0;
    for (let i = 0; i < n; i++) {
        const target = 2 * sorted_abs[i];
        let left = i + 1;
        let right = n - 1;
        let j = -1;
        while (left <= right) {
            const mid = Math.floor((left + right) / 2);
            if (sorted_abs[mid] <= target) {
                j = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        if (j >= i + 1) {
            count += j - i;
        }
    }
    return count;
}
